// handleKick handles the /kick command
func (s *Server) handleKick(c *Client, args []string) error {
	if len(args) < 1 {
		return &CommandError{"Usage: /kick <player_id> [reason]"}
	}
	targetPlayerID := args[0]
	reason := "No reason provided"
	if len(args) > 1 {
		reason = strings.Join(args[1:], " ")
	}

	s.clientsMux.RLock()
	targetClient, found := s.clients[targetPlayerID]
	s.clientsMux.RUnlock()

	if !found {
		return &CommandError{"Player " + targetPlayerID + " not found."}
	}

	log.Printf("Admin %s kicked %s for reason: %s", c.ID, targetPlayerID, reason)
	targetClient.SendMessage("Server", fmt.Sprintf("You have been kicked by %s for: %s", c.ID, reason))
	targetClient.disconnect() // Disconnect the target client
	c.SendMessage("Server", "You kicked player "+targetPlayerID+" for: "+reason)
	return nil
}

