// generateClientID provides a unique ID for a new client
func (s *Server) generateClientID() string {
	s.clientsMux.Lock()
	defer s.clientsMux.Unlock()
	s.nextClientID++
	return fmt.Sprintf("client-%d", s.nextClientID)
}

// handleWebSocket manages new websocket connections
func (s *Server) handleWebSocket(w http.ResponseWriter, r *http.Request) {
	conn, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Println("WebSocket upgrade failed:", err)
		return
	}

	clientID := s.generateClientID()

	// Extract roles from request headers.
	// For example, a client might send a header like: X-User-Roles: admin,moderator
	roleHeader := r.Header.Get("X-User-Roles")
	var roles []string
	if roleHeader != "" {
		roles = strings.Split(roleHeader, ",")
		for i, role := range roles {
			roles[i] = strings.TrimSpace(role)
		}
	}
	if len(roles) == 0 {
		roles = []string{"guest"} // Default role if none provided
	}

	client := &Client{
		conn:   conn,
		ID:     clientID,
		Roles:  roles,
		send:   make(chan []byte, 256),
		server: s, // Link client back to the server
	}

	s.clientsMux.Lock()
	s.clients[clientID] = client
	s.clientsMux.Unlock()

	log.Printf("Client %s connected with roles: %v", client.ID, client.Roles)
	client.SendMessage("Server", "Welcome, "+client.ID+"! Your roles: "+strings.Join(client.Roles, ", "))

	go client.writePump()
	go client.readPump()
}

// readPump reads messages from the websocket connection
func (c *Client) readPump() {
	defer func() {
		c.disconnect()
	}()
	c.conn.SetReadLimit(maxMessageSize)
	c.conn.SetReadDeadline(time.Now().Add(pongWait))
	c.conn.SetPongHandler(func(string) error { c.conn.SetReadDeadline(time.Now().Add(pongWait)); return nil })
	for {
		_, message, err := c.conn.ReadMessage()
		if err != nil {
			if websocket.IsUnexpectedCloseError(err, websocket.CloseGoingAway, websocket.CloseAbnormalClosure) {
				log.Printf("Client %s read error: %v", c.ID, err)
			}
			break
		}
		msgStr := string(message)
		log.Printf("Client %s received: %s", c.ID, msgStr)
		c.server.ParseAndExecute(c, msgStr) // Delegate command parsing to the server
	}
}

// writePump writes messages to the websocket connection
func (c *Client) writePump() {
	ticker := time.NewTicker(pingPeriod)
	defer func() {
		ticker.Stop()
		c.conn.Close()
	}()
	for {
		select {
		case message, ok := <-c.send:
			c.conn.SetWriteDeadline(time.Now().Add(writeWait))
			if !ok {
				// The server closed the channel.
				c.conn.WriteMessage(websocket.CloseMessage, []byte{})
				return
			}

			w, err := c.conn.NextWriter(websocket.TextMessage)
			if err != nil {
				return
			}
			w.Write(message)

			// Add queued messages to the current websocket message.
			n := len(c.send)
			for i := 0; i < n; i++ {
				w.Write([]byte("\n")) // Separator for multiple messages
				w.Write(<-c.send)
			}

			if err := w.Close(); err != nil {
				return
			}
		case <-ticker.C:
			c.conn.SetWriteDeadline(time.Now().Add(writeWait))
			if err := c.conn.WriteMessage(websocket.PingMessage, nil); err != nil {
				return
			}
		}
	}
}

// SendMessage sends a formatted message to the client
func (c *Client) SendMessage(sender, content string) {
	fullMsg := []byte(fmt.Sprintf("[%s] %s", sender, content))
	select {
	case c.send <- fullMsg:
	default:
		log.Printf("Client %s message send buffer full, dropping message: %s", c.ID, content)
	}
}

// SendError sends an error message to the client
func (c *Client) SendError(errorMessage string) {
	c.SendMessage("Error", errorMessage)
}

// disconnect removes the client from the server and closes the connection
func (c *Client) disconnect() {
	c.server.clientsMux.Lock()
	delete(c.server.clients, c.ID)
	c.server.clientsMux.Unlock()
	c.conn.Close()
	log.Printf("Client %s disconnected", c.ID)
	close(c.send)
}

// CommandError is a custom error type for command execution issues
type CommandError struct {
	Message string
}

func (e *CommandError) Error() string {
	return e.Message
}

